import React from "react";
import Navbar from "./Navbar";
import Sidebar from "./Sidebar";

function Layout({ children }) {
  return (
    <div>
      <Navbar />
      <div className="d-flex">
        <Sidebar />
        <div className="p-4 flex-grow-1 bg-light">{children}</div>
      </div>
    </div>
  );
}

export default Layout;
